---@class LBlockMiniGameBuffActor
local LBlockMiniGameBuffActor = LxClass("LBlockMiniGameBuffActor", nil)

function LBlockMiniGameBuffActor:LBlockMiniGameBuffActor(obj, ref)
    self._obj = obj

    self._trans = self._obj:GetTransform()

    -- 消行配置
    self._clearLineRef = ref

    self._endTime = ref.time

    -- 销毁
    self._isDestroy = false

    self:InitBuff()
end

-- 销毁
function LBlockMiniGameBuffActor:Destroy()
    self._isDestroy = true

    if self._eff then
        self._eff:Destroy()
        self._eff = nil
        self._effTrans = nil
    end
end

-- 销毁
function LBlockMiniGameBuffActor:IsDestroy()
    return self._isDestroy
end

-- 初始化buff
function LBlockMiniGameBuffActor:InitBuff()
    local ref = self._clearLineRef

    local buffMap = {}
    local list = string.split(ref.buffList, ",")
    for i, v in ipairs(list) do
        local list2 = string.split(v, "=")
        buffMap[list2[1]] = tonumber(list2[2])
    end

    local data = self._obj:GetData()
    for key, val in pairs(buffMap) do
        if key == "hp" then
            data:SetBuffHp(val)
        else
            local newVal = val + data:GetAttr(key)
            data:SetAttr(key, newVal)
        end
    end
    self._buffMap = buffMap

    self:PlayEffect()
end

-- 还原buff
function LBlockMiniGameBuffActor:RestoreBuff()
    if self._eff then
        self._eff:Destroy()
        self._eff = nil
        self._effTrans = nil
    end

    local data = self._obj:GetData()
    for key, val in pairs(self._buffMap) do
        if key == "hp" then
            data:SetBuffHp(0)
        else
            local newVal = data:GetAttr(key) - val
            data:SetAttr(key, newVal)
        end
    end
end

-- Update
function LBlockMiniGameBuffActor:Update(dt)
    if self._endTime then
        self._endTime = self._endTime - dt
        if self._endTime <= 0 then
            self:RestoreBuff()
            self._endTime = nil
        end
    end
end

-- 翻转X轴
function LBlockMiniGameBuffActor:UpDateFlipX()
    if self._effTrans then
        local flipX = self._obj:GetDpObject():IsFlipX()
        local scale = self._effTrans.localScale
        scale.x = math.abs(scale.x)
        if flipX then
            scale.x = -scale.x
            self._effTrans.localScale = scale
        else
            self._effTrans.localScale = scale
        end
    end
end

-- 播特效
function LBlockMiniGameBuffActor:PlayEffect()
    local dp = LDisplayEffect:New()
    dp:CreateEffect(self._trans, self._clearLineRef.buffFx)
    dp:SetResTag(CS.RES_TAG_SCENE)
    self._eff = dp
    dp:SetLoadedFunction(function()
        if self:IsDestroy() then
            return
        end

        self._effTrans = dp:GetDisplayTrans()
        self:UpDateFlipX()
    end)
    dp:StartLoadEffect()

end

-- 暂停
function LBlockMiniGameBuffActor:OnPauseGame()

end

-- 恢复
function LBlockMiniGameBuffActor:OnResumeGame()

end

return LBlockMiniGameBuffActor
